const question = $('Frage empfangen').first().json.body.question;
const results  = $input.first().json.results || [];

// Fakten als nummerierten Context aufbereiten
const factsText = results.map((r, i) => {
  const sources = (r.source_references || []).join(', ');
  const conf    = Math.round((r.confidence_score || 0) * 100);
  return `[${i+1}] (${conf}% Konfidenz) ${r.text}\n    Quellen: ${sources || '–'}`;
}).join('\n\n');

const systemPrompt = `Du bist ein präziser Factual Assistant. Beantworte die Frage AUSSCHLIESSLICH auf Basis der unten stehenden verifizierten Swiss Truth Claims.

Regeln:
- Antworte klar und präzise auf Deutsch
- Zitiere die relevanten Claims mit [N] in deiner Antwort
- Falls die Claims die Frage nicht vollständig beantworten, sage das explizit
- Erfinde keine Informationen die nicht in den Claims stehen
- Am Ende: liste die verwendeten Quellen auf`;

const userPrompt = `Frage: ${question}\n\nVerifizierte Fakten aus der Swiss Truth Wissensbasis:\n\n${factsText}`;

return [{
  json: {
    question,
    system_prompt: systemPrompt,
    user_prompt:   userPrompt,
    claims:        results.map(r => ({
      id:         r.id,
      text:       r.text,
      confidence: r.confidence_score,
      hash:       r.hash_sha256,
      sources:    r.source_references || []
    }))
  }
}];

const claudeResp = $input.first().json;
const context    = $('Context aufbereiten').first().json;

const answerText = claudeResp.content?.[0]?.text || 'Keine Antwort erhalten.';

// Alle einzigartigen Quellen aus verwendeten Claims sammeln
const allSources = [...new Set(
  (context.claims || []).flatMap(c => c.sources || [])
)];

return [{
  json: {
    question:        context.question,
    answer:          answerText,
    sources:         allSources,
    claims_used:     context.claims.length,
    claims:          context.claims.map(c => ({
      text:       c.text.substring(0, 120) + (c.text.length > 120 ? '…' : ''),
      confidence: c.confidence,
      hash:       c.hash,
      sources:    c.sources
    })),
    model:           claudeResp.model,
    powered_by:      'Swiss Truth MCP + Claude',
    mcp_endpoint:    'https://swisstruth.org/mcp'
  }
}];

